checker_dsl:
EXISTS (`taint flow path P`) {
  AND {
    EXISTS (`source node S`) {
      (`S is an instance of ActiveThreatModelSource`)
    },
    EXISTS (`sink node K`) {
      (`K is an instance of UrlRedirectSink`)
    },
    (`P is a taint flow path from S to K`),
    NOT {
      EXISTS (`barrier node B`) {
        AND {
          (`B is an instance of UrlRedirectSanitizer`),
          (`B lies on the taint flow path P between S and K`)
        }
      }
    }
  }
}
